let datasets = [];
try {
    if (typeof msg.payload === 'string' && msg.payload.length > 0) {
        datasets = JSON.parse(msg.payload);
    } else if (Array.isArray(msg.payload)) {
        datasets = msg.payload;
    }
} catch (err) {
    node.error('Failed to parse /data/dsp-config/datasets.json: ' + err.message);
    datasets = [];
}
if (!Array.isArray(datasets)) {
    node.error('datasets.json did not parse to a JSON array; got ' + typeof datasets);
    datasets = [];
}
flow.set('catalogue', datasets);
node.log('DSP catalogue: ' + datasets.length + ' dataset(s) loaded');
return null;

flow.set('catalogue', []);
node.warn('DSP catalogue: /data/dsp-config/datasets.json missing — serving empty catalogue. Mount the ConfigMap.');
return null;

// Mirrors catalogue_store.query_catalogue() filter + cursor logic.
const datasets = flow.get('catalogue') || [];
const body = (msg.payload && typeof msg.payload === 'object') ? msg.payload : {};
const filter = body.filter || {};
const page = body.page || {};

const limit = (typeof page.limit === 'number' && page.limit > 0) ? page.limit : 50;
const cursorRaw = page.cursor;

let filtered = datasets;
if (filter.assetType) {
    filtered = filtered.filter(d => d && d.metadata && d.metadata.assetType === filter.assetType);
}
if (Array.isArray(filter.datasetIds) && filter.datasetIds.length > 0) {
    const ids = new Set(filter.datasetIds);
    filtered = filtered.filter(d => d && ids.has(d.id));
}

// Python: int(cursor) on ValueError -> 0; missing/null -> 0.
let start = 0;
if (cursorRaw !== null && cursorRaw !== undefined && cursorRaw !== '') {
    const parsed = parseInt(cursorRaw, 10);
    start = Number.isFinite(parsed) && parsed >= 0 ? parsed : 0;
}

const slice = filtered.slice(start, start + limit);
const nextCursor = (start + limit) < filtered.length ? String(start + limit) : null;

msg.payload = { datasets: slice, nextCursor: nextCursor };
msg.headers = { 'Content-Type': 'application/json' };
msg.statusCode = 200;
return [msg, { payload: { family: 'facis_dsp_catalogue_requests_total' } }];
